class Solution:
    def numberOfLines(self, widths, s):
        lines = []
        cur = 0
        for ch in s:
            w = widths[ord(ch) - 97]
            if cur + w > 100:
                lines.append(cur)
                cur = w
            else:
                cur += w
        lines.append(cur)
        return [len(lines), lines[-1]]

