var numberOfLines = function(widths, s) {
    let lines = 1, cur = 0;
    for (const ch of s) {
        const w = widths[ch.charCodeAt(0) - 97];
        if (cur + w > 100) {
            lines += 1;
            cur = w;
        } else {
            cur += w;
        }
    }
    return [lines, cur];
